{
  "mode": "method",
  "tests": [
    {
      "name": "create_stats_history_valid",
      "input": {
        "handle": "john_doe",
        "payload": {
          "stats": [
            {
              "id": 1,
              "value": 100
            },
            {
              "value": 200
            }
          ]
        }
      },
      "output": {
        "status": "success",
        "message": "Stats history created"
      },
      "notes": "Valid input to create a new stats history entry."
    },
    {
      "name": "update_stats_history_partial",
      "input": {
        "handle": "john_doe",
        "payload": {
          "stats": [
            {
              "id": 1,
              "value": 150
            }
          ]
        }
      },
      "output": {
        "status": "success",
        "message": "Stats history updated"
      },
      "notes": "Partial update of existing stats history."
    },
    {
      "name": "create_stats_invalid_handle",
      "input": {
        "handle": "invalid_handle",
        "payload": {
          "stats": [
            {
              "value": 300
            }
          ]
        }
      },
      "output": {
        "status": "error",
        "message": "Member not found"
      },
      "notes": "Testing with an invalid member handle."
    },
    {
      "name": "update_stats_history_nonexistent_id",
      "input": {
        "handle": "john_doe",
        "payload": {
          "stats": [
            {
              "id": 999,
              "value": 250
            }
          ]
        }
      },
      "output": {
        "status": "error",
        "message": "Stats history item not found"
      },
      "notes": "Attempting to update a non-existent stats history item."
    },
    {
      "name": "create_member_stats_valid",
      "input": {
        "handle": "john_doe",
        "payload": {
          "stats": {
            "score": 500,
            "level": 5
          }
        }
      },
      "output": {
        "status": "success",
        "message": "Member stats created"
      },
      "notes": "Valid input to create member stats."
    },
    {
      "name": "update_member_stats_partial",
      "input": {
        "handle": "john_doe",
        "payload": {
          "stats": {
            "score": 600
          }
        }
      },
      "output": {
        "status": "success",
        "message": "Member stats updated"
      },
      "notes": "Partial update of existing member stats."
    },
    {
      "name": "create_stats_with_empty_payload",
      "input": {
        "handle": "john_doe",
        "payload": {}
      },
      "output": {
        "status": "error",
        "message": "Invalid payload"
      },
      "notes": "Testing with an empty payload for stats creation."
    },
    {
      "name": "update_stats_with_no_changes",
      "input": {
        "handle": "john_doe",
        "payload": {
          "stats": [
            {
              "id": 1,
              "value": 100
            }
          ]
        }
      },
      "output": {
        "status": "success",
        "message": "No changes made"
      },
      "notes": "Testing update with no changes to existing stats."
    }
  ],
  "assumptions": "Member handles are unique and valid.",
  "notes": "Ensure that the database is in a clean state before running tests."
